% Edit metadata fields here if needed. Default values are "none".

rows = cell(0, 9);
% <ColorKit_USER_PRESETS_BEGIN>
rows(end + 1, :) = {"My_Color_1", "Custom", "none", ["#95AFAD" "#BBCAE7" "#E5F7F6" "#FFF7C8" "#FFC5AC" "#FF8064"], "plot_line", "none", "none", "none", "none"};
