% <ColorKit_USER_PRESETS_END>

presets = struct('name', {}, 'category', {}, 'type', {}, 'anchors', {}, ...
    'recommendedUse', {}, 'isColorblindFriendly', {}, 'isPrintFriendly', {}, ...
    'centerColor', {}, 'sourceStyle', {}, 'matlabName', {}, 'nativeN', {});
if isempty(rows)
    return
end
presetTemplate = struct('name', "", 'category', "", 'type', "", 'anchors', strings(1, 0), ...
    'recommendedUse', "", 'isColorblindFriendly', "", 'isPrintFriendly', "", ...
    'centerColor', "", 'sourceStyle', "", 'matlabName', "", 'nativeN', []);
presets(1, size(rows, 1)) = presetTemplate;
for k = 1:size(rows, 1)
    presets(k) = struct('name', string(rows{k, 1}), ...
        'category', string(rows{k, 2}), 'type', string(rows{k, 3}), ...
        'anchors', string(rows{k, 4}), 'recommendedUse', string(rows{k, 5}), ...
        'isColorblindFriendly', string(rows{k, 6}), ...
        'isPrintFriendly', string(rows{k, 7}), 'centerColor', string(rows{k, 8}), ...
        'sourceStyle', string(rows{k, 9}), 'matlabName', "", 'nativeN', []);
end
end

